    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-only\n/*\n * kernel/power/suspend.c - Suspend to RAM and standby functionality.\n *\n * Copyright (c) 2003 Patrick Mochel\n * Copyright (c) 2003 Open Source Development Lab\n * Copyright (c) 2009 Rafael J. Wysocki <rjw@sisk.pl>, Novell Inc.\n */\n\n#define pr_fmt(fmt) \"PM: \" fmt\n\n#include <linux/string.h>\n#include <linux/delay.h>\n#include <linux/errno.h>\n#include <linux/init.h>\n#include <linux/console.h>\n#include <linux/cpu.h>\n#include <linux/cpuidle.h>\n#include <linux/gfp.h>\n#include <linux/io.h>\n#include <linux/kernel.h>\n#include <linux/list.h>\n#include <linux/mm.h>\n#include <linux/slab.h>\n#include <linux/export.h>\n#include <linux/suspend.h>\n#include <linux/syscore_ops.h>\n#include <linux/swait.h>\n#include <linux/ftrace.h>\n#include <trace/events/power.h>\n#include <linux/compiler.h>\n#include <linux/moduleparam.h>\n#include <linux/fs.h>\n\n#include \"power.h\"\n\nconst char * const pm_labels[] = {\n\t[PM_SUSPEND_TO_IDLE] = \"freeze\",\n\t[PM_SUSPEND_STANDBY] = \"standby\",\n\t[PM_SUSPEND_MEM] = \"mem\",\n};\nconst char *pm_states[PM_SUSPEND_MAX];\nstatic const char * const mem_sleep_labels[] = {\n\t[PM_SUSPEND_TO_IDLE] = \"s2idle\",\n\t[PM_SUSPEND_STANDBY] = \"shallow\",\n\t[PM_SUSPEND_MEM] = \"deep\",\n};\nconst char *mem_sleep_states[PM_SUSPEND_MAX];\n\nsuspend_state_t mem_sleep_current = PM_SUSPEND_TO_IDLE;\nsuspend_state_t mem_sleep_default = PM_SUSPEND_MAX;\nsuspend_state_t pm_suspend_target_state;\nEXPORT_SYMBOL_GPL(pm_suspend_target_state);\n\nunsigned int pm_suspend_global_flags;\nEXPORT_SYMBOL_GPL(pm_suspend_global_flags);\n\nstatic const struct platform_suspend_ops *suspend_ops;\nstatic const struct platform_s2idle_ops *s2idle_ops;\nstatic DECLARE_SWAIT_QUEUE_HEAD(s2idle_wait_head);\n\nenum s2idle_states __read_mostly s2idle_state;\nstatic DEFINE_RAW_SPINLOCK(s2idle_lock);\n\n/**\n * pm_suspend_default_s2idle - Check if suspend-to-idle is the default suspend.\n *\n * Return 'true' if suspend-to-idle has been selected as the default system\n * suspend method.\n */\nbool pm_suspend_default_s2idle(void)\n{\n\treturn mem_sleep_current == PM_SUSPEND_TO_IDLE;\n}\nEXPORT_SYMBOL_GPL(pm_suspend_default_s2idle);\n\nvoid s2idle_set_ops(const struct platform_s2idle_ops *ops)\n{\n\tunsigned int sleep_flags;\n\n\tsleep_flags = lock_system_sleep();\n\ts2idle_ops = ops;\n\tunlock_system_sleep(sleep_flags);\n}\n\nstatic void s2idle_begin(void)\n{\n\ts2idle_state = S2IDLE_STATE_NONE;\n}\n\nstatic void s2idle_enter(void)\n{\n\ttrace_suspend_resume(TPS(\"machine_suspend\"), PM_SUSPEND_TO_IDLE, true);\n\n\t/*\n\t * The correctness of the code below depends on the number of online\n\t * CPUs being stable, but CPUs cannot be taken offline or put online\n\t * while it is running.\n\t *\n\t * The s2idle_lock must be acquired before the pending wakeup check to\n\t * prevent pm_system_wakeup() from running as a whole between that check\n\t * and the subsequent s2idle_state update in which case a wakeup event\n\t * would get lost.\n\t */\n\traw_spin_lock_irq(&s2idle_lock);\n\tif (pm_wakeup_pending())\n\t\tgoto out;\n\n\ts2idle_state = S2IDLE_STATE_ENTER;\n\traw_spin_unlock_irq(&s2idle_lock);\n\n\t/* Push all the CPUs into the idle loop. */\n\twake_up_all_idle_cpus();\n\t/* Make the current CPU wait so it can enter the idle loop too. */\n\tswait_event_exclusive(s2idle_wait_head,\n\t\t    s2idle_state == S2IDLE_STATE_WAKE);\n\n\t/*\n\t * Kick all CPUs to ensure that they resume their timers and restore\n\t * consistent system state.\n\t */\n\twake_up_all_idle_cpus();\n\n\traw_spin_lock_irq(&s2idle_lock);\n\n out:\n\ts2idle_state = S2IDLE_STATE_NONE;\n\traw_spin_unlock_irq(&s2idle_lock);\n\n\ttrace_suspend_resume(TPS(\"machine_suspend\"), PM_SUSPEND_TO_IDLE, false);\n}\n\nstatic void s2idle_loop(void)\n{\n\tpm_pr_dbg(\"suspend-to-idle\\n\");\n\n\t/*\n\t * Suspend-to-idle equals:\n\t * frozen processes + suspended devices + idle processors.\n\t * Thus s2idle_enter() should be called right after all devices have\n\t * been suspended.\n\t *\n\t * Wakeups during the noirq suspend of devices may be spurious, so try\n\t * to avoid them upfront.\n\t */\n\tfor (;;) {\n\t\tif (s2idle_ops && s2idle_ops->wake) {\n\t\t\tif (s2idle_ops->wake())\n\t\t\t\tbreak;\n\t\t} else if (pm_wakeup_pending()) {\n\t\t\tbreak;\n\t\t}\n\n\t\tif (s2idle_ops && s2idle_ops->check)\n\t\t\ts2idle_ops->check();\n\n\t\ts2idle_enter();\n\t}\n\n\tpm_pr_dbg(\"resume from suspend-to-idle\\n\");\n}\n\nvoid s2idle_wake(void)\n{\n\tunsigned long flags;\n\n\traw_spin_lock_irqsave(&s2idle_lock, flags);\n\tif (s2idle_state > S2IDLE_STATE_NONE) {\n\t\ts2idle_state = S2IDLE_STATE_WAKE;\n\t\tswake_up_one(&s2idle_wait_head);\n\t}\n\traw_spin_unlock_irqrestore(&s2idle_lock, flags);\n}\nEXPORT_SYMBOL_GPL(s2idle_wake);\n\nstatic bool valid_state(suspend_state_t state)\n{\n\t/*\n\t * The PM_SUSPEND_STANDBY and PM_SUSPEND_MEM states require low-level\n\t * support and need to be valid to the low-level implementation.\n\t *\n\t * No ->valid() or ->enter() callback implies that none are valid.\n\t */\n\treturn suspend_ops && suspend_ops->valid && suspend_ops->valid(state) &&\n\t\tsuspend_ops->enter;\n}\n\nvoid __init pm_states_init(void)\n{\n\t/* \"mem\" and \"freeze\" are always present in /sys/power/state. */\n\tpm_states[PM_SUSPEND_MEM] = pm_labels[PM_SUSPEND_MEM];\n\tpm_states[PM_SUSPEND_TO_IDLE] = pm_labels[PM_SUSPEND_TO_IDLE];\n\t/*\n\t * Suspend-to-idle should be supported even without any suspend_ops,\n\t * initialize mem_sleep_states[] accordingly here.\n\t */\n\tmem_sleep_states[PM_SUSPEND_TO_IDLE] = mem_sleep_labels[PM_SUSPEND_TO_IDLE];\n}\n\nstatic int __init mem_sleep_default_setup(char *str)\n{\n\tsuspend_state_t state;\n\n\tfor (state = PM_SUSPEND_TO_IDLE; state <= PM_SUSPEND_MEM; state++)\n\t\tif (mem_sleep_labels[state] &&\n\t\t    !strcmp(str, mem_sleep_labels[state])) {\n\t\t\tmem_sleep_default = state;\n\t\t\tmem_sleep_current = state;\n\t\t\tbreak;\n\t\t}\n\n\treturn 1;\n}\n__setup(\"mem_sleep_default=\", mem_sleep_default_setup);\n\n/**\n * suspend_set_ops - Set the global suspend method table.\n * @ops: Suspend operations to use.\n */\nvoid suspend_set_ops(const struct platform_suspend_ops *ops)\n{\n\tunsigned int sleep_flags;\n\n\tsleep_flags = lock_system_sleep();\n\n\tsuspend_ops = ops;\n\n\tif (valid_state(PM_SUSPEND_STANDBY)) {\n\t\tmem_sleep_states[PM_SUSPEND_STANDBY] = mem_sleep_labels[PM_SUSPEND_STANDBY];\n\t\tpm_states[PM_SUSPEND_STANDBY] = pm_labels[PM_SUSPEND_STANDBY];\n\t\tif (mem_sleep_default == PM_SUSPEND_STANDBY)\n\t\t\tmem_sleep_current = PM_SUSPEND_STANDBY;\n\t}\n\tif (valid_state(PM_SUSPEND_MEM)) {\n\t\tmem_sleep_states[PM_SUSPEND_MEM] = mem_sleep_labels[PM_SUSPEND_MEM];\n\t\tif (mem_sleep_default >= PM_SUSPEND_MEM)\n\t\t\tmem_sleep_current = PM_SUSPEND_MEM;\n\t}\n\n\tunlock_system_sleep(sleep_flags);\n}\nEXPORT_SYMBOL_GPL(suspend_set_ops);\n\n/**\n * suspend_valid_only_mem - Generic memory-only valid callback.\n * @state: Target system sleep state.\n *\n * Platform drivers that implement mem suspend only and only need to check for\n * that in their .valid() callback can use this instead of rolling their own\n * .valid() callback.\n */\nint suspend_valid_only_mem(suspend_state_t state)\n{\n\treturn state == PM_SUSPEND_MEM;\n}\nEXPORT_SYMBOL_GPL(suspend_valid_only_mem);\n\nstatic bool sleep_state_supported(suspend_state_t state)\n{\n\treturn state == PM_SUSPEND_TO_IDLE ||\n\t       (valid_state(state) && !cxl_mem_active());\n}\n\nstatic int platform_suspend_prepare(suspend_state_t state)\n{\n\treturn state != PM_SUSPEND_TO_IDLE && suspend_ops->prepare ?\n\t\tsuspend_ops->prepare() : 0;\n}\n\nstatic int platform_suspend_prepare_late(suspend_state_t state)\n{\n\treturn state == PM_SUSPEND_TO_IDLE && s2idle_ops && s2idle_ops->prepare ?\n\t\ts2idle_ops->prepare() : 0;\n}\n\nstatic int platform_suspend_prepare_noirq(suspend_state_t state)\n{\n\tif (state == PM_SUSPEND_TO_IDLE)\n\t\treturn s2idle_ops && s2idle_ops->prepare_late ?\n\t\t\ts2idle_ops->prepare_late() : 0;\n\n\treturn suspend_ops->prepare_late ? suspend_ops->prepare_late() : 0;\n}\n\nstatic void platform_resume_noirq(suspend_state_t state)\n{\n\tif (state == PM_SUSPEND_TO_IDLE) {\n\t\tif (s2idle_ops && s2idle_ops->restore_early)\n\t\t\ts2idle_ops->restore_early();\n\t} else if (suspend_ops->wake) {\n\t\tsuspend_ops->wake();\n\t}\n}\n\nstatic void platform_resume_early(suspend_state_t state)\n{\n\tif (state == PM_SUSPEND_TO_IDLE && s2idle_ops && s2idle_ops->restore)\n\t\ts2idle_ops->restore();\n}\n\nstatic void platform_resume_finish(suspend_state_t state)\n{\n\tif (state != PM_SUSPEND_TO_IDLE && suspend_ops->finish)\n\t\tsuspend_ops->finish();\n}\n\nstatic int platform_suspend_begin(suspend_state_t state)\n{\n\tif (state == PM_SUSPEND_TO_IDLE && s2idle_ops && s2idle_ops->begin)\n\t\treturn s2idle_ops->begin();\n\telse if (suspend_ops && suspend_ops->begin)\n\t\treturn suspend_ops->begin(state);\n\telse\n\t\treturn 0;\n}\n\nstatic void platform_resume_end(suspend_state_t state)\n{\n\tif (state == PM_SUSPEND_TO_IDLE && s2idle_ops && s2idle_ops->end)\n\t\ts2idle_ops->end();\n\telse if (suspend_ops && suspend_ops->end)\n\t\tsuspend_ops->end();\n}\n\nstatic void platform_recover(suspend_state_t state)\n{\n\tif (state != PM_SUSPEND_TO_IDLE && suspend_ops->recover)\n\t\tsuspend_ops->recover();\n}\n\nstatic bool platform_suspend_again(suspend_state_t state)\n{\n\treturn state != PM_SUSPEND_TO_IDLE && suspend_ops->suspend_again ?\n\t\tsuspend_ops->suspend_again() : false;\n}\n\n#ifdef CONFIG_PM_DEBUG\nstatic unsigned int pm_test_delay = 5;\nmodule_param(pm_test_delay, uint, 0644);\nMODULE_PARM_DESC(pm_test_delay,\n\t\t \"Number of seconds to wait before resuming from suspend test\");\n#endif\n\nstatic int suspend_test(int level)\n{\n#ifdef CONFIG_PM_DEBUG\n\tint i;\n\n\tif (pm_test_level == level) {\n\t\tpr_info(\"suspend debug: Waiting for %d second(s).\\n\",\n\t\t\t\tpm_test_delay);\n\t\tfor (i = 0; i < pm_test_delay && !pm_wakeup_pending(); i++) {\n\t\t\tif (level > TEST_CORE)\n\t\t\t\tmsleep(1000);\n\t\t\telse\n\t\t\t\tmdelay(1000);\n\t\t}\n\t\treturn 1;\n\t}\n#endif /* !CONFIG_PM_DEBUG */\n\treturn 0;\n}\n\n/**\n * suspend_prepare - Prepare for entering system sleep state.\n * @state: Target system sleep state.\n *\n * Common code run for every system sleep state that can be entered (except for\n * hibernation).  Run suspend notifiers, allocate the \"suspend\" console and\n * freeze processes.\n */\nstatic int suspend_prepare(suspend_state_t state)\n{\n\tint error;\n\n\tif (!sleep_state_supported(state))\n\t\treturn -EPERM;\n\n\tpm_prepare_console();\n\n\terror = pm_notifier_call_chain_robust(PM_SUSPEND_PREPARE, PM_POST_SUSPEND);\n\tif (error)\n\t\tgoto Restore;\n\n\tfilesystems_freeze(filesystem_freeze_enabled);\n\ttrace_suspend_resume(TPS(\"freeze_processes\"), 0, true);\n\terror = suspend_freeze_processes();\n\ttrace_suspend_resume(TPS(\"freeze_processes\"), 0, false);\n\tif (!error)\n\t\treturn 0;\n\n\tdpm_save_failed_step(SUSPEND_FREEZE);\n\tfilesystems_thaw();\n\tpm_notifier_call_chain(PM_POST_SUSPEND);\n Restore:\n\tpm_restore_console();\n\treturn error;\n}\n\n/* default implementation */\nvoid __weak arch_suspend_disable_irqs(void)\n{\n\tlocal_irq_disable();\n}\n\n/* default implementation */\nvoid __weak arch_suspend_enable_irqs(void)\n{\n\tlocal_irq_enable();\n}\n\n/**\n * suspend_enter - Make the system enter the given sleep state.\n * @state: System sleep state to enter.\n * @wakeup: Returns information that the sleep state should not be re-entered.\n *\n * This function should be called after devices have been suspended.\n */\nstatic int suspend_enter(suspend_state_t state, bool *wakeup)\n{\n\tint error;\n\n\terror = platform_suspend_prepare(state);\n\tif (error)\n\t\tgoto Platform_finish;\n\n\terror = dpm_suspend_late(PMSG_SUSPEND);\n\tif (error) {\n\t\tpr_err(\"late suspend of devices failed\\n\");\n\t\tgoto Platform_finish;\n\t}\n\terror = platform_susp