    "content": "{"content":"int hibernation_snapshot(int platform_mode)\n{\n\tpm_message_t msg;\n\tint error;\n\n\tpm_suspend_clear_flags();\n\terror = platform_begin(platform_mode);\n\tif (error)\n\t\tgoto Close;\n\n\t/* Preallocate image memory before shutting down devices. */\n\terror = hibernate_preallocate_memory();\n\tif (error)\n\t\tgoto Close;\n\n\terror = freeze_kernel_threads();\n\tif (error)\n\t\tgoto Cleanup;\n\n\tif (hibernation_test(TEST_FREEZER)) {\n\n\t\t/*\n\t\t * Indicate to the caller that we are returning due to a\n\t\t * successful freezer test.\n\t\t */\n\t\tfreezer_test_done = true;\n\t\tgoto Thaw;\n\t}\n\n\terror = dpm_prepare(PMSG_FREEZE);\n\tif (error) {\n\t\tdpm_complete(PMSG_RECOVER);\n\t\tgoto Thaw;\n\t}\n\n\t/*\n\t * Device drivers may move lots of data to shmem in dpm_prepare(). The shmem\n\t * pages will use lots of system memory, causing hibernation image creation\n\t * fail due to insufficient free memory.\n\t * This call is to force flush the shmem pages to swap disk and reclaim\n\t * the system memory so that image creation can succeed.\n\t */\n\tshrink_shmem_memory();\n\n\tconsole_suspend_all();\n\tpm_restrict_gfp_mask();\n\n\terror = dpm_suspend(PMSG_FREEZE);\n\n\tif (error || hibernation_test(TEST_DEVICES))\n\t\tplatform_recover(platform_mode);\n\telse\n\t\terror = create_image(platform_mode);\n\n\t/*\n\t * In the case that we call create_image() above, the control\n\t * returns here (1) after the image has been created or the\n\t * image creation has failed and (2) after a successful restore.\n\t */\n\n\t/* We may need to release the preallocated image pages here. */\n\tif (error || !in_suspend)\n\t\tswsusp_free();\n\n\tmsg = in_suspend ? (error ? PMSG_RECOVER : PMSG_THAW) : PMSG_RESTORE;\n\tdpm_resume(msg);\n\n\tif (error || !in_suspend)\n\t\tpm_restore_gfp_mask();\n\n\tconsole_resume_all();\n\tdpm_complete(msg);\n\n Close:\n\tplatform_end(platform_mode);\n\treturn error;\n\n Thaw:\n\tthaw_kernel_threads();\n Cleanup:\n\tswsusp_free();\n\tgoto Close;\n}\n\nint __weak hibernate_resume_nonboot_cpu_disable(void)\n{\n\treturn suspend_disable_secondary_cpus();\n}\n\n/**\n * resume_target_kernel - Restore system state from a hibernation image.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Execute device drivers' \"noirq\" and \"late\" freeze callbacks, restore the\n * contents of highmem that have not been restored yet from the image and run\n * the low-level code that will restore the remaining contents of memory and\n * switch to the just restored target kernel.\n */\nstatic int resume_target_kernel(bool platform_mode)\n{\n\tint error;\n\n\terror = dpm_suspend_end(PMSG_QUIESCE);\n\tif (error) {\n\t\tpr_err(\"Some devices failed to power down, aborting resume\\n\");\n\t\treturn error;\n\t}\n\n\terror = platform_pre_restore(platform_mode);\n\tif (error)\n\t\tgoto Cleanup;\n\n\tcpuidle_pause();\n\n\terror = hibernate_resume_nonboot_cpu_disable();\n\tif (error)\n\t\tgoto Enable_cpus;\n\n\tlocal_irq_disable();\n\tsystem_state = SYSTEM_SUSPEND;\n\n\terror = syscore_suspend();\n\tif (error)\n\t\tgoto Enable_irqs;\n\n\tsave_processor_state();\n\terror = restore_highmem();\n\tif (!error) {\n\t\terror = swsusp_arch_resume();\n\t\t/*\n\t\t * The code below is only ever reached in case of a failure.\n\t\t * Otherwise, execution continues at the place where\n\t\t * swsusp_arch_suspend() was called.\n\t\t */\n\t\tBUG_ON(!error);\n\t\t/*\n\t\t * This call to restore_highmem() reverts the changes made by\n\t\t * the previous one.\n\t\t */\n\t\trestore_highmem();\n\t}\n\t/*\n\t * The only reason why swsusp_arch_resume() can fail is memory being\n\t * very tight, so we have to free it as soon as we can to avoid\n\t * subsequent failures.\n\t */\n\tswsusp_free();\n\trestore_processor_state();\n\ttouch_softlockup_watchdog();\n\n\tsyscore_resume();\n\n Enable_irqs:\n\tsystem_state = SYSTEM_RUNNING;\n\tlocal_irq_enable();\n\n Enable_cpus:\n\tpm_sleep_enable_secondary_cpus();\n\n Cleanup:\n\tplatform_restore_cleanup(platform_mode);\n\n\tdpm_resume_start(PMSG_RECOVER);\n\n\treturn error;\n}\n\n/**\n * hibernation_restore - Quiesce devices and restore from a hibernation image.\n * @platform_mode: If set, use platform driver to prepare for the transition.\n *\n * This routine must be called with system_transition_mutex held.  If it is\n * successful, control reappears in the restored target kernel in\n * hibernation_snapshot().\n */\nint hibernation_restore(int platform_mode)\n{\n\tint error;\n\n\tpm_prepare_console();\n\tconsole_suspend_all();\n\terror = dpm_suspend_start(PMSG_QUIESCE);\n\tif (!error) {\n\t\terror = resume_target_kernel(platform_mode);\n\t\t/*\n\t\t * The above should either succeed and jump to the new kernel,\n\t\t * or return with an error. Otherwise things are just\n\t\t * undefined, so let's be paranoid.\n\t\t */\n\t\tBUG_ON(!error);\n\t}\n\tdpm_resume_end(PMSG_RECOVER);\n\tconsole_resume_all();\n\tpm_restore_console();\n\treturn error;\n}\n\n/**\n * hibernation_platform_enter - Power off the system using the platform driver.\n */\nint hibernation_platform_enter(void)\n{\n\tint error;\n\n\tif (!hibernation_ops)\n\t\treturn -ENOSYS;\n\n\t/*\n\t * We have cancelled the power transition by running\n\t * hibernation_ops->finish() before saving the image, so we should let\n\t * the firmware know that we're going to enter the sleep state after all\n\t */\n\terror = hibernation_ops->begin(PMSG_HIBERNATE);\n\tif (error)\n\t\tgoto Close;\n\n\tentering_platform_hibernation = true;\n\tconsole_suspend_all();\n\terror = dpm_suspend_start(PMSG_HIBERNATE);\n\tif (error) {\n\t\tif (hibernation_ops->recover)\n\t\t\thibernation_ops->recover();\n\t\tgoto Resume_devices;\n\t}\n\n\terror = dpm_suspend_end(PMSG_HIBERNATE);\n\tif (error)\n\t\tgoto Resume_devices;\n\n\terror = hibernation_ops->prepare();\n\tif (error)\n\t\tgoto Platform_finish;\n\n\terror = pm_sleep_disable_secondary_cpus();\n\tif (error)\n\t\tgoto Enable_cpus;\n\n\tlocal_irq_disable();\n\tsystem_state = SYSTEM_SUSPEND;\n\n\terror = syscore_suspend();\n\tif (error)\n\t\tgoto Enable_irqs;\n\n\tif (pm_wakeup_pending()) {\n\t\terror = -EAGAIN;\n\t\tgoto Power_up;\n\t}\n\n\thibernation_ops->enter();\n\t/* We should never get here */\n\twhile (1);\n\n Power_up:\n\tsyscore_resume();\n Enable_irqs:\n\tsystem_state = SYSTEM_RUNNING;\n\tlocal_irq_enable();\n\n Enable_cpus:\n\tpm_sleep_enable_secondary_cpus();\n\n Platform_finish:\n\thibernation_ops->finish();\n\n\tdpm_resume_start(PMSG_RESTORE);\n\n Resume_devices:\n\tentering_platform_hibernation = false;\n\tdpm_resume_end(PMSG_RESTORE);\n\tconsole_resume_all();\n\n Close:\n\thibernation_ops->end();\n\n\treturn error;\n}\n\n/**\n * power_down - Shut the machine down for hibernation.\n *\n * Use the platform driver, if configured, to put the system into the sleep\n * state corresponding to hibernation, or try to power it off or reboot,\n * depending on the value of hibernation_mode.\n */\nstatic void power_down(void)\n{\n\tint error;\n\n#ifdef CONFIG_SUSPEND\n\tif (hibernation_mode == HIBERNATION_SUSPEND) {\n\t\terror = suspend_devices_and_enter(mem_sleep_current);\n\t\tif (!error)\n\t\t\tgoto exit;\n\n\t\thibernation_mode = hibernation_ops ? HIBERNATION_PLATFORM :\n\t\t\t\t\t\t     HIBERNATION_SHUTDOWN;\n\t}\n#endif\n\n\tswitch (hibernation_mode) {\n\tcase HIBERNATION_REBOOT:\n\t\tkernel_restart(NULL);\n\t\tbreak;\n\tcase HIBERNATION_PLATFORM:\n\t\terror = hibernation_platform_enter();\n\t\tif (error == -EAGAIN || error == -EBUSY) {\n\t\t\tevents_check_enabled = false;\n\t\t\tpr_info(\"Wakeup event detected during hibernation, rolling back.\\n\");\n\t\t\tgoto exit;\n\t\t}\n\t\tfallthrough;\n\tcase HIBERNATION_SHUTDOWN:\n\t\tif (kernel_can_power_off()) {\n\t\t\tentering_platform_hibernation = true;\n\t\t\tkernel_power_off();\n\t\t\tentering_platform_hibernation = false;\n\t\t}\n\t\tbreak;\n\t}\n\tkernel_halt();\n\t/*\n\t * Valid image is on the disk, if we continue we risk serious data\n\t * corruption after resume.\n\t */\n\tpr_crit(\"Power down manually\\n\");\n\twhile (1)\n\t\tcpu_relax();\n\nexit:\n\t/* Restore swap signature. */\n\terror = swsusp_unmark();\n\tif (error)\n\t\tpr_err(\"Swap will be unusable! Try swapon -a.\\n\");\n}\n\nstatic int load_image_and_restore(void)\n{\n\tint error;\n\tunsigned int flags;\n\n\tpm_pr_dbg(\"Loading hibernation image.\\n\");\n\n\tlock_device_hotplug();\n\terror = create_basic_memory_bitmaps();\n\tif (error) {\n\t\tswsusp_close();\n\t\tgoto Unlock;\n\t}\n\n\terror = swsusp_read(&flags);\n\tswsusp_close();\n\tif (!error)\n\t\terror = hibernation_restore(flags & SF_PLATFORM_MODE);\n\n\tpr_err(\"Failed to load image, recovering.\\n\");\n\tswsusp_free();\n\tfree_basic_memory_bitmaps();\n Unlock:\n\tunlock_device_hotplug();\n\n\treturn error;\n}\n\n#define COMPRESSION_ALGO_LZO \"lzo\"\n#define COMPRESSION_ALGO_LZ4 \"lz4\"\n\n/**\n * hibernate - Carry out system hibernation, including saving the image.\n */\nint hibernate(void)\n{\n\tbool snapshot_test = false;\n\tunsigned int sleep_flags;\n\tint error;\n\n\tif (!hibernation_available()) {\n\t\tpm_pr_dbg(\"Hibernation not available.\\n\");\n\t\treturn -EPERM;\n\t}\n\n\t/*\n\t * Query for the compression algorithm support if compression is enabled.\n\t */\n\tif (!nocompress) {\n\t\tstrscpy(hib_comp_algo, hibernate_compressor);\n\t\tif (!crypto_has_acomp(hib_comp_algo, 0, CRYPTO_ALG_ASYNC)) {\n\t\t\tpr_err(\"%s compression is not available\\n\", hib_comp_algo);\n\t\t\treturn -EOPNOTSUPP;\n\t\t}\n\t}\n\n\tsleep_flags = lock_system_sleep();\n\t/* The snapshot device should not be opened while we're running */\n\tif (!hibernate_acquire()) {\n\t\terror = -EBUSY;\n\t\tgoto Unlock;\n\t}\n\n\tpr_info(\"hibernation entry\\n\");\n\tpm_prepare_console();\n\terror = pm_notifier_call_chain_robust(PM_HIBERNATION_PREPARE, PM_POST_HIBERNATION);\n\tif (error)\n\t\tgoto Restore;\n\n\terror = pm_sleep_fs_sync();\n\tif (error)\n\t\tgoto Notify;\n\n\tfilesystems_freeze(filesystem_freeze_enabled);\n\n\terror = freeze_processes();\n\tif (error)\n\t\tgoto Exit;\n\n\tlock_device_hotplug();\n\t/* Allocate memory management structures */\n\terror = create_basic_memory_bitmaps();\n\tif (error)\n\t\tgoto Thaw;\n\n\terror = hibernation_snapshot(hibernation_mode == HIBERNATION_PLATFORM);\n\tif (error || freezer_test_done)\n\t\tgoto Free_bitmaps;\n\n\tif (in_suspend) {\n\t\tunsigned int flags = 0;\n\n\t\tif (hibernation_mode == HIBERNATION_PLATFORM)\n\t\t\tflags |= SF_PLATFORM_MODE;\n\t\tif (nocompress) {\n\t\t\tflags |= SF_NOCOMPRESS_MODE;\n\t\t} else {\n\t\t        flags |= SF_CRC32_MODE;\n\n\t\t\t/*\n\t\t\t * By default, LZO compression is enabled. Use SF_COMPRESSION_ALG_LZ4\n\t\t\t * to override this behaviour and use LZ4.\n\t\t\t *\n\t\t\t * Refer kernel/power/power.h for more details\n\t\t\t */\n\n\t\t\tif (!strcmp(hib_comp_algo, COMPRESSION_ALGO_LZ4))\n\t\t\t\tflags |= SF_COMPRESSION_ALG_LZ4;\n\t\t\telse\n\t\t\t\tflags |= SF_COMPRESSION_ALG_LZO;\n\t\t}\n\n\t\tpm_pr_dbg(\"Writing hibernation image.\\n\");\n\t\terror = swsusp_write(flags);\n\t\tswsusp_free();\n\t\tif (!error) {\n\t\t\tif (hibernation_mode == HIBERNATION_TEST_RESUME)\n\t\t\t\tsnapshot_test = true;\n\t\t\telse\n\t\t\t\tpower_down();\n\t\t}\n\t\tin_suspend = 0;\n\t\tpm_restore_gfp_mask();\n\t} else {\n\t\tpm_pr_dbg(\"Hibernation image restored successfully.\\n\");\n\t}\n\n Free_bitmaps:\n\tfree_basic_memory_bitmaps();\n Thaw:\n\tunlock_device_hotplug();\n\tif (snapshot_test) {\n\t\tpm_pr_dbg(\"Checking hibernation image\\n\");\n\t\terror = swsusp_check(false);\n\t\tif (!error)\n\t\t\terror = load_image_and_restore();\n\t}\n\tthaw_processes();\n\n\t/* Don't bother checking whether freezer_test_done is true */\n\tfreezer_test_done = false;\n Exit:\n\tfilesystems_thaw();\n Notify:\n\tpm_notifier_call_chain(PM_POST_HIBERNATION);\n Restore:\n\tpm_restore_console();\n\thibernate_release();\n Unlock:\n\tunlock_system_sleep(sleep_flags);\n\tpr_info(\"hibernation exit\\n\");\n\n\treturn error;\n}\n\n/**\n * hibernate_quiet_exec - Execute a function with all devices frozen.\n * @func: Function to execute.\n * @data: Data pointer to pass to @func.\n *\n * Return the @func return value or an error code if it cannot be executed.\n */\nint hibernate_quiet_exec(int (*func)(void *data), void *data)\n{\n\tunsigned int sleep_flags;\n\tint error;\n\n\tsleep_flags = lock_system_sleep();\n\n\tif (!hibernate_acquire()) {\n\t\terror = -EBUSY;\n\t\tgoto unlock;\n\t}\n\n\tpm_prepare_console();\n\n\terror = pm_notifier_call_chain_robust(PM_HIBERNATION_PREPARE, PM_POST_HIBERNATION);\n\tif (error)\n\t\tgoto restore;\n\n\tfilesystems_freeze(filesystem_freeze_enabled);\n\n\terror = freeze_processes();\n\tif (error)\n\t\tgoto exit;\n\n\tlock_device_hotplug();\n\n\tpm_suspend_clear_flags();\n\n\terror = platform_begin(true);\n\tif (error)\n\t\tgoto thaw;\n\n\terror = freeze_kernel_threads();\n\tif (error)\n\t\tgoto thaw;\n\n\terror = dpm_prepare(PMSG_FREEZE);\n\tif (error)\n\t\tgoto dpm_complete;\n\n\tconsole_suspend_all();\n\n\terror = dpm_suspend(PMSG_FREEZE);\n\tif (error)\n\t\tgoto dpm_resume;\n\n\terror = dpm_suspend_end(PMSG_FREEZE);\n\tif (error)\n\t\tgoto dpm_resume;\n\n\terror = platform_pre_snapshot(true);\n\tif (error)\n\t\tgoto skip;\n\n\terror = func(data);\n\nskip:\n\tplatform_finish(true);\n\n\tdpm_resume_start(PMSG_THAW);\n\ndpm_resume:\n\tdpm_resume(PMSG_THAW);\n\n\tconsole_resume_all();\n\ndpm_complete:\n\tdpm_complete(PMSG_THAW);\n\n\tthaw_kernel_threads();\n\nthaw:\n\tplatform_end(true);\n\n\tunlock_device_hotplug();\n\n\tthaw_processes();\n\nexit:\n\tfilesystems_thaw();\n\tpm_notifier_call_chain(PM_POST_HIBERNATION);\n\nrestore:\n\tpm_restore_console();\n\n\thibernate_release();\n\nunlock:\n\tunlock_system_sleep(sleep_flags);\n\n\treturn error;\n}\nEXPORT_SYMBOL_GPL(hibernate_quiet_exec);\n\nstatic int __init find_resume_device(void)\n{\n\tif (!strlen(resume_file))\n\t\treturn -ENOENT;\n\n\tpm_pr_dbg(\"Checking hibernation image partition %s\\n\", resume_file);\n\n\tif (resume_delay) {\n\t\tpr_info(\"Waiting %dsec before reading resume device ...\\n\",\n\t\t\tresume_delay);\n\t\tssleep(resume_delay);\n\t}\n\n\t/* Check if the device is there */\n\tif (!early_lookup_bdev(resume_file, &swsusp_resume_device))\n\t\treturn 0;\n\n\t/*\n\t * Some device discovery might still be in progress; we need to wait for\n\t * this to finish.\n\t */\n\twait_for_device_probe();\n\tif (resume_wait) {\n\t\twhile (early_lookup_bdev(resume_file, &swsusp_resume_device))\n\t\t\tmsleep(10);\n\t\tasync_synchronize_full();\n\t}\n\n\treturn early_lookup_bdev(resume_file, &swsusp_resume_device);\n}\n\nstatic int software_resume(void)\n{\n\tint error;\n\n\tpm_pr_dbg(\"Hibernation image partition %d:%d present\\n\",\n\t\tMAJOR(swsusp_resume_device), MINOR(swsusp_resume_device));\n\n\tpm_pr_dbg(\"Looking for hibernation image.\\n\");\n\n\tmutex_lock(&system_transition_mutex);\n\terror = swsusp_check(true);\n\tif (error)\n\t\tgoto Unlock;\n\n\t/*\n\t * Check if the hibernation image is compressed. If so, query for\n\t * the algorithm support.\n\t */\n\tif (!(swsusp_header_flags & SF_NOCOMPRESS_MODE)) {\n\t\tif (swsusp_header_flags & SF_COMPRESSION_ALG_LZ4)\n\t\t\tstrscpy(hib_comp_algo, COMPRESSION_ALGO_LZ4);\n\t\telse\n\t\t\tstrscpy(hib_comp_algo, COMPRESSION_ALGO_LZO);\n\t\tif (!crypto_has_acomp(hib_comp_algo, 0, CRYPTO_ALG_ASYNC)) {\n\t\t\tpr_err(\"%s compression is not available\\n\", hib_comp_algo);\n\t\t\terror = -EOPNOTSUPP;\n\t\t\tgoto Unlock;\n\t\t}\n\t}\n\n\t/* The snapshot device should not be opened while we're running */\n\tif (!hibernate_acquire()) {\n\t\terror = -EBUSY;\n\t\tswsusp_close();\n\t\tgoto Unlock;\n\t}\n\n\tpr_info(\"resume from hibernation\\n\");\n\tpm_prepare_console();\n\terror = pm_notifier_call_chain_robust(PM_RESTORE_PREPARE, PM_POST_RESTORE);\n\tif (error)\n\t\tgoto Restore;\n\n\tfilesystems_freeze(filesystem_freeze_enabled);\n\n\tpm_pr_dbg(\"Preparing processes for hibernation restore.\\n\");\n\terror = freeze_processes();\n\tif (error) {\n\t\tfilesystems_thaw();\n\t\tgoto Close_Finish;\n\t}\n\n\terror = freeze_kernel_threads();\n\tif (error) {\n\t\tthaw_processes();\n\t\tfilesystems_thaw();\n\t\tgoto Close_Finish;\n\t}\n\n\terror = load_image_and_restore();\n\tthaw_processes();\n\tfilesystems_thaw();\n Finish:\n\tpm_notifier_call_chain(PM_POST_RESTORE);\n Restore:\n\tpm_restore_console();\n\tpr_info(\"resume failed (%d)\\n\", error);\n\thibernate_release();\n\t/* For success case, the suspend path will release the lock */\n Unlock:\n\tmutex_unlock(&system_transition_mutex);\n\tpm_pr_dbg(\"Hibernation image not present or could not be loaded.\\n\");\n\treturn error;\n Close_Finish:\n\tswsusp_close();\n\tgoto Finish;\n}\n\n/**\n * software_resume_initcall - Resume from a saved hibernation image.\n *\n * This routine is called as a late initcall, when all devices have been\n * discovered and initialized already.\n *\n * The image reading code is called to see if there is a hibernation image\n * available for reading.  If that is the case, devices are quiesced and the\n * contents of memory is restored from the saved image.\n *\n * If this is successful, control reappears in the restored target kernel in\n * hibernation_snapshot() which returns to hibernate().  Otherwise, the routine\n * attempts to recover gracefully and make the kernel return to the normal mode\n * of operation.\n */\nstatic int __init software_resume_initcall(void)\n{\n\t/*\n\t * If the user said \"noresume\".. bail out early.\n\t */\n\tif (noresume || !hibernation_available())\n\t\treturn 0;\n\n\tif (!swsusp_resume_device) {\n\t\tint error = find_resume_device();\n\n\t\tif (error)\n\t\t\treturn error;\n\t}\n\n\treturn software_resume();\n}\nlate_initcall_sync(software_resume_initcall);\n\n\nstatic const char * const hibernation_modes[] = {\n\t[HIBERNATION_PLATFORM]\t= \"platform\",\n\t[HIBERNATION_SHUTDOWN]\t= \"shutdown\",\n\t[HIBERNATION_REBOOT]\t= \"reboot\",\n#ifdef CONFIG_SUSPEND\n\t[HIBERNATION_SUSPEND]\t= \"suspend\",\n#endif\n\t[HIBERNATION_TEST_RESUME]\t= \"test_resume\",\n};\n\n/*\n * /sys/power/disk - Control hibernation mode.\n *\n * Hibernation can be handled in several ways.  There are a few different ways\n * to put the system into the sleep state: using the platform driver (e.g. ACPI\n * or other hibernation_ops), powering it off or rebooting it (for testing\n * mostly).\n *\n * The sysfs file /sys/power/disk provides an interface for selecting the\n * hibernation mode to use.  Reading from this file causes the available modes\n * to be printed.  There are 3 modes that can be supported:\n *\n *\t'platform'\n *\t'shutdown'\n *\t'reboot'\n *\n * If a platform hibernation driver is in use, 'platform' will be supported\n * and will be used by default.  Otherwise, 'shutdown' will be used by default.\n * The selected option (i.e. the one corresponding to the current value of\n * hibernation_mode) is enclosed by a square bracket.\n *\n * To select a given hibernation mode it is necessary to write the mode's\n * string representation (as returned by reading from /sys/power/disk) back\n * into /sys/power/disk.\n */\n\nstatic ssize_t disk_show(struct kobject *kobj, struct kobj_attribute *attr,\n\t\t\t char *buf)\n{\n\tssize_t count = 0;\n\tint i;\n\n\tif (!hibernation_available())\n\t\treturn sysfs_emit(buf, \"[disabled]\\n\");\n\n\tfor (i = HIBERNATION_FIRST; i <= HIBERNATION_MAX; i++) {\n\t\tif (!hibernation_modes[i])\n\t\t\tcontinue;\n\t\tswitch (i) {\n\t\tcase HIBERNATION_SHUTDOWN:\n\t\tcase HIBERNATION_REBOOT:\n#ifdef CONFIG_SUSPEND\n\t\tcase HIBERNATION_SUSPEND:\n#endif\n\t\tcase HIBERNATION_TEST_RESUME:\n\t\t\tbreak;\n\t\tcase HIBERNATION_PLATFORM:\n\t\t\tif (hibernation_ops)\n\t\t\t\tbreak;\n\t\t\t/* not a valid mode, continue with loop */\n\t\t\tcontinue;\n\t\t}\n\t\tif (i == hibernation_mode)\n\t\t\tcount += sysfs_emit_at(buf, count, \"[%s] \", hibernation_modes[i]);\n\t\telse\n\t\t\tcount += sysfs_emit_at(buf, count, \"%s \", hibernation_modes[i]);\n\t}\n\n\t/* Convert the last